  ('judicial-f0899a01-moex-00466', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政罰法之規定，一行為違反行政法上義務而受罰鍰之處分，該處罰之法律另有沒入之規定時，下列敘 述何者正確？', '["一行為不二罰，因此不得再作沒入處分", "需視裁處處分與沒入處分何者較重，擇一重者處罰之", "兩者可合併處罰", "如應沒入之物品有危害大眾之可能時，始可一併沒入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00467', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政罰法規定，下列何者為裁處罰鍰須審酌之事項？', '["因違反行政法上義務所得之利益", "有無涉嫌違反刑事法律", "受處罰者之人數", "受處罰者之經歷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00468', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '某甲因欠繳稅款，經主管機關催告限期履行後仍未履行，其名下之房屋因而遭到執行機關之查封。倘若甲 對於該查封處分不服，應如何提起救濟？', '["向主管機關提起復查", "向執行機關聲明異議", "向執行機關提起訴願", "向主管機關提起訴願"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00469', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政執行法規定，下列何者非屬義務人不得管收之情形？', '["生產後3月未滿", "現罹疾病，恐因管收而不能治療", "懷胎5月以上", "因管收而其一家生計有難以維持之虞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00470', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於聽證之敘述，下列何者錯誤？', '["聽證以不公開為原則，不開放旁聽", "行政機關得於聽證期日前舉行預備聽證", "聽證主持人得由行政機關首長指定之", "行政機關未經當事人之申請，亦得變更聽證期日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00471', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列應限制公開之政府資訊，何者基於公益之必要仍得公開？', '["公開足以妨害刑事被告受公正之裁判者", "政府機關為實施監督業務，而取得監督對象之相關資料，其公開將對實施目的造成困難或妨害者", "為保存文化資產必須特別管理，而公開有滅失或減損其價值之虞者", "公開有侵害個人隱私、職業上秘密或著作權人之公開發表權者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00472', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列事項何者仍須適用行政程序法之程序規定？', '["外國人出、入境之行為", "刑事案件犯罪偵查程序", "對公務人員所為一次記二大過免職之處分", "考試院有關考選命題及評分之行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00473', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '若對於當事人之送達，因應為送達之處所不明，以黏貼於行政機關公告欄、但未同時刊登政府公報或新聞 紙之方式對應受送達人為公示送達。關於此送達之效力，下列敘述何者正確？', '["因未送達於當事人本人，不發生送達之效果", "自公告之翌日起生效", "自公告之日起，經20日發生效力", "自公告黏貼於公告欄最後之日起，經30日發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00474', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依訴願法第77條規定，下列何者非屬訴願應不受理之情形？', '["對於命拆除違建之行政處分提起訴願後，該違建於地震中倒塌", "財政部國有財產署拒絕人民要求讓售國有財產，人民提起訴願", "原處分未附救濟期間之教示，於原處分書送達後2個月提起訴願", "人民因違反噪音管制法提起訴願並已作成決定後，再次提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
